 13→/**
 14→ * Response from bulk delete operation
 15→ */
 16→export interface BulkDeleteResult {
 17→  deletedAssets: number;
 18→  deletedVulnerabilities: number;
 19→  deletedScanResults: number;
 20→  message: string;
 21→}
 22→
 23→/**
 24→ * Response from import operation
 25→ */
 26→export interface ImportResult {
 27→  message: string;
 28→  imported: number;
 29→  skipped: number;
