 35→/**
 36→ * Delete all assets (ADMIN only)
 37→ * User Story 1: Bulk Delete Assets
 38→ *
 39→ * @returns BulkDeleteResult with counts of deleted entities
 40→ * @throws Error on 403 (forbidden), 409 (conflict), 500 (server error)
 41→ */
 42→export async function bulkDeleteAssets(): Promise<BulkDeleteResult> {
 43→  const response = await authenticatedDelete('/api/assets/bulk');
 44→
 45→  if (response.ok) {
 46→    return await response.json();
 47→  }
 48→
 49→  // Handle error responses
 50→  if (response.status === 403) {
 51→    throw new Error('Insufficient permissions. ADMIN role required.');
 52→  }
 53→
 54→  if (response.status === 409) {
 55→    const error = await response.json();
 56→    throw new Error(error.error || 'Bulk asset deletion already in progress');
 57→  }
 58→
 59→  if (response.status === 500) {
 60→    const error = await response.json();
 61→    throw new Error(error.error || 'Bulk delete failed. No assets were deleted.');
 62→  }
 63→
 64→  throw new Error(`Failed to delete assets: ${response.status}`);
 65→}
